 81→export function NotificationsScreen({navigation}: Props) {
 82→  const {session} = useAuth();
 83→  const {colors} = useTheme();
 84→  const token = session?.access_token ?? '';
 85→  const userId = session?.user.id ?? '';
 86→
 87→  const notificationsQuery = useQuery({
 88→    queryKey: ['notifications', userId],
 89→    enabled: Boolean(token),
 90→    queryFn: () => mobileApi.getNotifications(token, null, 30),
 91→  });
 92→
 93→  const unreadCountQuery = useQuery({
 94→    queryKey: ['notification-count', userId],
 95→    enabled: Boolean(token && userId),
 96→    queryFn: () => socialApi.getNotificationsCount(token, userId),
 97→  });
 98→
 99→  const markReadMutation = useMutation({
100→    mutationFn: (args: {notifId: string; source: 'journal' | 'opinion'}) =>
101→      socialApi.markNotificationRead(token, args.notifId, args.source),
102→    onSuccess: () => {
103→      queryClient.invalidateQueries({queryKey: ['notifications', userId]});
104→      queryClient.invalidateQueries({queryKey: ['notification-count', userId]});
105→    },
106→  });
107→
108→  const deleteMutation = useMutation({
109→    mutationFn: (args: {notifId: string; source: 'journal' | 'opinion'}) =>
110→      socialApi.deleteNotification(token, args.notifId, args.source),
111→    onSuccess: () => {
112→      queryClient.invalidateQueries({queryKey: ['notifications', userId]});
113→      queryClient.invalidateQueries({queryKey: ['notification-count', userId]});
114→    },
115→  });
116→
117→  const items = notificationsQuery.data?.data ?? [];
118→  const unreadCount = unreadCountQuery.data?.count ?? 0;
119→
120→  const handlePress = (item: NotificationItem) => {
121→    if (!item.read) {
122→      markReadMutation.mutate({notifId: item.id, source: getSource(item)});
123→    }
124→    if (item.journal_id) {
125→      navigation.navigate('PostDetail', {journalId: item.journal_id});
126→    }
127→  };
128→
129→  const renderItem = ({item}: {item: NotificationItem}) => {
130→    const subtitle = formatContext(item);
131→    const isUnread = !item.read;
132→
133→    return (
134→      <Pressable
135→        onPress={() => handlePress(item)}
136→        style={[
137→          styles.card,
138→          {
139→            backgroundColor: isUnread ? colors.bgSelection : colors.bgCard,
140→            borderColor: colors.borderCard,
141→          },
142→        ]}>
143→        <View style={styles.avatarWrap}>
144→          <Avatar
145→            uri={item.users?.image_url}
146→            name={item.users?.name ?? undefined}
147→            size={40}
148→          />
149→          <View
150→            style={[
151→              styles.iconBadge,
152→              {backgroundColor: colors.bgElevated, borderColor: colors.borderLight},
153→            ]}>
154→            <NotifIcon type={item.type} color={colors.accentAmber} />
155→          </View>
156→        </View>
157→
158→        <View style={styles.textSection}>
159→          <Text
160→            style={[
161→              styles.cardTitle,
162→              {color: colors.textPrimary},
163→              isUnread && styles.unreadTitle,
164→            ]}
165→            numberOfLines={2}>
166→            {formatTitle(item)}
167→          </Text>
168→          {!!subtitle && (
169→            <Text
170→              style={[styles.cardSubtitle, {color: colors.textMuted}]}
171→              numberOfLines={1}>
172→              {subtitle}
173→            </Text>
174→          )}
175→          <Text style={[styles.timestamp, {color: colors.textFaint}]}>
176→            {formatRelativeDate(item.created_at)}
177→          </Text>
178→        </View>
179→
180→        {isUnread && (
181→          <View style={[styles.unreadDot, {backgroundColor: colors.accentAmber}]} />
182→        )}
183→      </Pressable>
184→    );
185→  };
186→
187→  return (
188→    <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]} edges={['top']}>
189→      <View style={styles.header}>
190→        <Text style={[styles.title, {color: colors.textHeading}]}>
191→          Notifications
192→        </Text>
193→        {unreadCount > 0 && (
194→          <View style={[styles.countBadge, {backgroundColor: colors.accentAmber}]}>
195→            <Text style={styles.countText}>{unreadCount}</Text>
196→          </View>
197→        )}
198→      </View>
199→
200→      {!token ? (
201→        <EmptyState title="Sign in" subtitle="Log in to see your notifications" />
202→      ) : notificationsQuery.isLoading ? (
203→        <View style={styles.loading}>
204→          <ActivityIndicator color={colors.loaderColor} />
205→        </View>
206→      ) : (
207→        <FlatList
208→          data={items}
209→          keyExtractor={item => item.id}
210→          renderItem={renderItem}
211→          showsVerticalScrollIndicator={false}
212→          contentContainerStyle={styles.listContent}
213→          onRefresh={() => notificationsQuery.refetch()}
214→          refreshing={false}
215→          ListEmptyComponent={
216→            <EmptyState
217→              icon={<BellIcon size={36} color={colors.textFaint} />}
218→              title="All caught up"
219→              subtitle="No notifications yet"
220→            />
221→          }
222→        />
223→      )}
224→    </SafeAreaView>
225→  );
226→}
